import math
import random

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a

def is_prime(n, k=5):
    if n < 2:
        return False
    if n == 2 or n == 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False

    s = 0
    d = n - 1
    while d % 2 == 0:
        d //= 2
        s += 1

    for _ in range(k):
        a = random.randint(2, n - 2)
        x = pow(a, d, n)
        if x == 1 or x == n - 1:
            continue

        for _ in range(s - 1):
            x = pow(x, 2, n)
            if x == n - 1:
                break
        else:
            return False

    return True

def pollard_rho(n):
    if n % 2 == 0:
        return 2

    x = random.randint(2, n - 1)
    y = x
    c = random.randint(1, n - 1)
    d = 1

    def f(val):
        return (val * val + c) % n

    while d == 1:
        x = f(x)
        y = f(f(y))
        d = gcd(abs(x - y), n)

        if d == n:
            x = random.randint(2, n - 1)
            y = x
            c = random.randint(1, n - 1)
            d = 1

    return d

def prime_factorization(n):
    if n < 2:
        return []

    factors = []

    while n % 2 == 0:
        factors.append(2)
        n //= 2
    while n % 3 == 0:
        factors.append(3)
        n //= 3

    stack = [n]

    while stack:
        current_n = stack.pop()

        if current_n == 1:
            continue

        if is_prime(current_n):
            factors.append(current_n)
            continue

        factor = pollard_rho(current_n)

        stack.append(factor)
        stack.append(current_n // factor)

    factors.sort()
    return factors
